            60% { transform: rotate(-4deg) scale(1.01); }
            80% { transform: rotate(2deg) scale(1); }
            100% { transform: rotate(0deg) scale(1); }
        }

        /* 编钟发光效果 */
        .bell-glow {
            animation: bellGlow 0.6s ease-out;
