        function playClassicPiece(pieceId) {
            initAudio();

            // 如果正在播放录音，先停止它
            if (isPlaying) {
                stopPlayback();
            }

            // 如果正在播放，先停止
            if (isPlayingClassic) {
                stopClassicPiece();
                hidePlaybackStatus();
                // 如果点击的是当前播放的曲目，只停止不重新播放
                const clickedItem = document.querySelector(`[data-piece-id="${pieceId}"]`);
                if (clickedItem && clickedItem.classList.contains('playing')) {
                    return;
                }
            }

            const piece = classicPieces[pieceId];
            if (!piece) return;

            isPlayingClassic = true;
            showPlaybackStatus(piece.name, 'classic');
            showToast(`正在播放：${piece.name}`);

            // 更新UI状态
            document.querySelectorAll('.classic-item').forEach(item => {
                item.classList.remove('playing');
            });
            document.querySelector(`[data-piece-id="${pieceId}"]`)?.classList.add('playing');

